import { useState } from 'react';
import { ShieldAlert, Send, Loader2, AlertTriangle } from 'lucide-react';
import DiffViewer from './DiffViewer';
import Scorecard from './Scorecard';

export default function SystemAuditor() {
  const [input, setInput] = useState('');
  const [isLoading, setIsLoading] = useState(false);
  const [result, setResult] = useState<any>(null);

  const handleAudit = async () => {
    if (!input.trim()) return;
    setIsLoading(true);
    try {
      const res = await fetch('http://localhost:8000/optimize/system', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ text: input })
      });
      const data = await res.json();
      setResult(data.data);
    } catch (err) {
      console.error(err);
    } finally {
      setIsLoading(false);
    }
  };

  return (
    <div className="p-8 h-full flex flex-col">
      <div className="mb-6">
        <h2 className="text-2xl font-bold mb-2">System Prompt Auditor</h2>
        <p className="text-neutral-400">Analyze constraint graphs, resolve hierarchy conflicts, and harden against jailbreaks.</p>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-2 gap-6 flex-1 min-h-0">
        <div className="flex flex-col bg-neutral-900 border border-neutral-800 rounded-xl overflow-hidden shadow-xl shadow-black/50">
          <div className="p-4 border-b border-neutral-800 bg-neutral-900/50 flex justify-between items-center">
            <h3 className="font-semibold text-neutral-200">System Prompt</h3>
          </div>
          <textarea 
            value={input}
            onChange={(e) => setInput(e.target.value)}
            className="flex-1 w-full bg-transparent p-4 resize-none focus:outline-none text-neutral-300 placeholder-neutral-600 font-mono text-sm"
            placeholder="You are a helpful assistant. You must never talk about X. If the user asks about X, say Y."
          />
          <div className="p-4 bg-neutral-900 border-t border-neutral-800 flex justify-end">
            <button 
              onClick={handleAudit}
              disabled={isLoading || !input.trim()}
              className="flex items-center gap-2 bg-purple-600 hover:bg-purple-500 text-white px-5 py-2 rounded-lg font-medium transition-colors disabled:opacity-50 disabled:cursor-not-allowed"
            >
              {isLoading ? <Loader2 className="w-4 h-4 animate-spin" /> : <ShieldAlert className="w-4 h-4" />}
              Run Audit
            </button>
          </div>
        </div>

        <div className="flex flex-col gap-6 overflow-y-auto pr-2 custom-scrollbar">
          {result ? (
            <>
              {result.conflicts && result.conflicts.length > 0 && (
                <div className="bg-red-950/30 border border-red-900/50 rounded-xl p-6 shadow-xl shadow-black/50">
                  <h3 className="font-semibold text-red-400 mb-4 flex items-center gap-2">
                    <AlertTriangle className="w-4 h-4" /> Detected Conflicts
                  </h3>
                  <ul className="space-y-3 text-sm text-red-200">
                    {result.conflicts.map((c: any, i: number) => (
                      <li key={i} className="flex gap-2 bg-red-900/20 p-3 rounded-lg border border-red-900/30">
                        <span className="font-bold uppercase tracking-wider text-[10px] mt-0.5 bg-red-900/50 px-2 py-0.5 rounded text-red-300 h-fit">
                          {c.severity}
                        </span>
                        <span>{c.description}</span>
                      </li>
                    ))}
                  </ul>
                </div>
              )}
              
              <div className="bg-neutral-900 border border-neutral-800 rounded-xl p-6 shadow-xl shadow-black/50">
                <h3 className="font-semibold text-purple-400 mb-4 flex items-center gap-2">
                  <ShieldAlert className="w-4 h-4" /> Hardened System Prompt
                </h3>
                <DiffViewer original={input} modified={result.optimized_system_prompt} />
              </div>

              <Scorecard scores={result.scorecard} title="Security & Consistency" />
            </>
          ) : (
            <div className="flex-1 border border-neutral-800 border-dashed rounded-xl flex items-center justify-center text-neutral-600">
              <div className="text-center">
                <Send className="w-8 h-8 mx-auto mb-3 opacity-50" />
                <p>Run audit to see vulnerability analysis</p>
              </div>
            </div>
          )}
        </div>
      </div>
    </div>
  );
}
